class Solution {
public:
    int numberOfArrays(string s, int k) {
        int n = s.size();
        vector<int> dp(n + 1);
        dp[0] = 1;
        int mod = 1e9 + 7;
        for (int i = 1; i <= n; ++i) {
            if (s[i - 1] == '0') continue;
            for (int j = i; j <= n; ++j) {
                long long num = stoll(s.substr(i - 1, j - i + 1));
                if (num > k) break;
                dp[j] = (dp[j] + dp[i - 1]) % mod;
            }
        }
        return dp[n];
    }
};
